+    #[test]
+    fn complex_trace_basic() {
+        // [[1+2i, 3], [0, 4-i]] → trace = (1+2i) + (4-i) = 5+i
+        let a = [1.0, 2.0, 3.0, 0.0, 0.0, 0.0, 4.0, -1.0];
+        let (tr, ti) = complex_trace_nxn(&a, 2).expect("trace");
+        assert!((tr - 5.0).abs() < 1e-15);
+        assert!((ti - 1.0).abs() < 1e-15);
